import React, {useState} from 'react'
import {useSelector, useDispatch} from 'react-redux'
import styled from 'styled-components'
import {messageSelector, setSidebarCategoryActive} from '../redux/messageSlice'


const Hr = styled.div `
width:0;
height:1px;
background-color:#1C1C1C;
transition:all 0.3s ease-in;
`

const Messages = styled.div `
${props => props.active && `color:#1C1C1C;& ${Hr} {width:100%;}`}
transition:all 0.5s ease-in-out;
&:hover {
	cursor:pointer;
	color:#1C1C1C;
}
&:hover ${Hr} {
	width:100%;
	color:#1C1C1C;
}
`

const MyItems = styled.div `
${props => props.active && `color:#1C1C1C;& ${Hr} {width:100%;}`}
transition:all 0.5s ease-in-out;
margin-top:20px;
&:hover {
	cursor:pointer;
	color:#1C1C1C;
}
&:hover ${Hr} {
	width:100%;
}
`

const MyProfile = styled.div `
${props => props.active && `color:#1C1C1C;& ${Hr} {width:100%;}`}
transition:all 0.5s ease-in-out;
margin-top:20px;
&:hover {
	cursor:pointer;
	color:#1C1C1C;
}
&:hover ${Hr} {
	width:100%;
}
`

const Settings = styled.div `
${props => props.active && `color:#1C1C1C;& ${Hr} {width:100%;}`}
transition:all 0.5s ease-in-out;
margin-top:20px;
&:hover {
	cursor:pointer;
	color:#1C1C1C;
}
&:hover ${Hr} {
	width:100%;
}
`

const LeftBodyPart = styled.div `
font-size:0.9rem;
width:20%;
display:flex;
justify-content:center;
align-items:flex-start;
flex-direction:column;
color:grey;
`


export default function MeSidebar () {
	/*const initialState = {
		messageActive:true,
		myItemsActive:false,
		myProfileActive:false,
		settingsActive:false
	}


	const [active, setActive] = useState(initialState)*/

	const dispatch = useDispatch()
	const message = useSelector(messageSelector)

	const onMessageClick = () => {
		//setActive({...initialState, messageActive:true})
		dispatch(setSidebarCategoryActive({messageActive:'messageActive', myItemsActive:'myItemsActive', myProfileActive:'myProfileActive', settingsActive:'settingsActive'}))
	}

	const onMyItemsClick = () => {
		//setActive({...initialState, myItemsActive:true, messageActive:false})
		dispatch(setSidebarCategoryActive('myItemsActive'))
	}

	const onMyProfileClick = () => {
		//setActive({...initialState, myProfileActive:true, messageActive:false})
		dispatch(setSidebarCategoryActive('myProfileActive'))
	}

	const onSettingsClick = () => {
		//setActive({...initialState, settingsActive:true, messageActive:false})
		dispatch(setSidebarCategoryActive('settingsActive'))
	}

	return (
		<LeftBodyPart>
			<Messages active={ message.messageActive} onClick={onMessageClick}>Messages<Hr /></Messages>
			<MyItems active={ message.myItemsActive} onClick={onMyItemsClick}>My Items<Hr /></MyItems>
			<MyProfile active={ message.myProfileActive} onClick={onMyProfileClick}>My Profile<Hr /></MyProfile>
			<Settings active={ message.settingsActive} onClick={onSettingsClick}>Settings<Hr /></Settings>
		</LeftBodyPart>
	)
}
